65	// ── Canonical-fixture identities ─────────────────────────────
66	
67	/// Canonical RBRR prefix bases installed by case 1. Distinct from pristine's
68	/// throwaway prefix bases (prlc/prlr); per-station tincture from BURS is
69	/// composed in at runtime so parallel-station runs land in disjoint cloud
70	/// names. Case 2's probe detects canonical state by reading the moniker's
71	/// family stem (also tinctured) from rbrr.env.
72	pub(crate) const RBTDRK_CANONICAL_CLOUD_BASE: &str = "canc";
73	pub(crate) const RBTDRK_CANONICAL_RUNTIME_BASE: &str = "canr";
74	
75	/// Family-stem base for canonical depots; six-digit auto-increment suffix per
76	/// run. Depots persist post-success for operator inspection; reruns pick the
77	/// next free suffix by walking depot_list output. Per-station tincture is
78	/// composed in at runtime so each station's monikers fact-file-walk against
79	/// a disjoint family stem. Era-bumped past `canest` and `canest2` to
80	/// side-step pending-delete projectId reservations from burned-bridges
81	/// teardown. The `canest2` bump was forced when the prior gmail-identity
82	/// payor's deleted `canest2bhm100000` depot held the global projectId in
83	/// DELETE_REQUESTED: project IDs are globally unique and reserved ~30 days
84	/// post-delete, and the active-only, single-identity allocator re-derives a
85	/// reserved ID it can neither see nor own.
86	pub(crate) const RBTDRK_FAMILY_STEM_BASE: &str = "canest3";
87	
88	/// Static identities for the canonical SA cycle. Stable across runs because
89	/// each run uses a fresh canest depot project.
90	const RBTDRK_IDENTITY_RETRIEVER: &str = "canest-ret";
91	const RBTDRK_IDENTITY_DIRECTOR: &str = "canest-dir";
92	
93	const RBTDRK_FAMILY_NUMERIC_FLOOR: u32 = 100000;
94	const RBTDRK_FAMILY_NUMERIC_WIDTH: usize = 6;
95	
96	// rbgp_depot_list emits fact files at
97	// `<cloud_prefix>/<moniker>.depot` (state) and
98	// `<cloud_prefix>/<moniker>.depot-project` (project_id). The cloud_prefix
99	// subdir prevents collisions between same-moniker depots under different
100	// cloud_prefixes.
101	const RBTDRK_FACT_EXT_DEPOT: &str = "depot";
102	const RBTDRK_FACT_EXT_DEPOT_PROJECT: &str = "depot-project";
103	const RBTDRK_FACT_GOVERNOR_SA_EMAIL: &str = "rbgp_fact_governor_sa_email";
104	
105	const RBTDRK_FIELD_RBRD_CLOUD_PREFIX: &str = "RBRD_CLOUD_PREFIX";
106	const RBTDRK_FIELD_RBRR_RUNTIME_PREFIX: &str = "RBRR_RUNTIME_PREFIX";
107	const RBTDRK_FIELD_RBRD_DEPOT_MONIKER: &str = "RBRD_DEPOT_MONIKER";
108	const RBTDRK_FIELD_RBRR_SECRETS_DIR: &str = "RBRR_SECRETS_DIR";
109	
110	/// BURS station-file env var (exported by bul_launcher.sh) — absolute path
111	/// to the developer's burs.env. Source for BURS_TINCTURE.
112	const RBTDRK_ENV_STATION_FILE: &str = "BURD_STATION_FILE";
113	
114	/// Read BURS_TINCTURE from the station file resolved via BURD_STATION_FILE.
115	/// BURS validation upstream (zburs_enforce) guarantees the value is 1-3 chars
116	/// of lowercase alphanumeric starting with a letter.
117	pub(crate) fn rbtdrk_burs_tincture() -> Result<String, String> {
118	    let path = rbtdrx_path_from_env(RBTDRK_ENV_STATION_FILE)?;
119	    rbtdrk_read_env_value(&path, "BURS_TINCTURE")
120	        .ok_or_else(|| format!("BURS_TINCTURE not in {}", path.display()))
121	}
122	
123	/// Compose canonical RBRD_CLOUD_PREFIX with the given tincture.
124	pub(crate) fn rbtdrk_canonical_cloud_prefix(tincture: &str) -> String {
125	    format!("{}{}-", RBTDRK_CANONICAL_CLOUD_BASE, tincture)
126	}
127	
128	/// Compose canonical RBRR_RUNTIME_PREFIX with the given tincture.
129	pub(crate) fn rbtdrk_canonical_runtime_prefix(tincture: &str) -> String {
130	    format!("{}{}-", RBTDRK_CANONICAL_RUNTIME_BASE, tincture)
131	}
132	
133	/// Compose canonical family stem with the given tincture.
134	pub(crate) fn rbtdrk_family_stem(tincture: &str) -> String {
135	    format!("{}{}", RBTDRK_FAMILY_STEM_BASE, tincture)
136	}
