185	fn rbtdrk_git_add_and_commit(root: &Path, file: &str, message: &str) -> Result<(), String> {
186	    rbtdrk_git_add_and_commit_paths(root, &[file], message)
187	}
188	
189	fn rbtdrk_git_add_and_commit_paths(
190	    root: &Path,
191	    files: &[&str],
192	    message: &str,
193	) -> Result<(), String> {
194	    let mut add_args: Vec<&str> = vec!["add"];
195	    add_args.extend_from_slice(files);
196	    let add = Command::new("git")
197	        .args(&add_args)
198	        .current_dir(root)
199	        .output()
200	        .map_err(|e| format!("rbtdrk: git add invocation failed: {}", e))?;
201	    if !add.status.success() {
202	        return Err(format!(
203	            "rbtdrk: git add failed (exit {}): {}",
204	            add.status.code().unwrap_or(-1),
205	            String::from_utf8_lossy(&add.stderr).trim()
206	        ));
207	    }
208	    let commit = Command::new("git")
209	        .args(["commit", "-m", message])
210	        .current_dir(root)
211	        .output()
212	        .map_err(|e| format!("rbtdrk: git commit invocation failed: {}", e))?;
213	    if !commit.status.success() {
214	        return Err(format!(
215	            "rbtdrk: git commit failed (exit {}): {}",
216	            commit.status.code().unwrap_or(-1),
217	            String::from_utf8_lossy(&commit.stderr).trim()
218	        ));
219	    }
220	    Ok(())
221	}
222	
223	/// Resolve canonical RBRA path for a role: <RBRR_SECRETS_DIR>/<role>/rbra.env.
224	pub(crate) fn rbtdrk_canonical_rbra(root: &Path, role: &str) -> Result<PathBuf, String> {
225	    let rbrr = root.join(RBTDGC_RBRR_FILE);
226	    let secrets_dir = rbtdrk_read_env_value(&rbrr, RBTDRK_FIELD_RBRR_SECRETS_DIR)
227	        .ok_or_else(|| format!("RBRR_SECRETS_DIR missing from {}", rbrr.display()))?;
228	    if secrets_dir.is_empty() {
229	        return Err(format!("RBRR_SECRETS_DIR is blank in {}", rbrr.display()));
230	    }
231	    Ok(rbtdrk_resolve(root, &secrets_dir)
232	        .join(role)
233	        .join(RBTDGC_RBRA_FILE))
234	}
235	
236	// ── Canonical-prefix install (case 1) ───────────────────────
237	
238	/// Idempotently install canc-/canr- prefixes. CLOUD_PREFIX lands in rbrd.env,
239	/// RUNTIME_PREFIX lands in rbrr.env. Returns Ok without committing when both
240	/// already match the canonical markers; otherwise rewrites both files and
241	/// commits in one go.
242	pub(crate) fn rbtdrk_install_canonical_prefixes(root: &Path) -> Result<(), String> {
243	    let rbrr = root.join(RBTDGC_RBRR_FILE);
244	    let rbrd = root.join(RBTDGC_RBRD_FILE);
245	    let tincture = rbtdrk_burs_tincture()?;
246	    let cloud_target = rbtdrk_canonical_cloud_prefix(&tincture);
247	    let runtime_target = rbtdrk_canonical_runtime_prefix(&tincture);
248	
249	    let cloud = rbtdrk_read_env_value(&rbrd, RBTDRK_FIELD_RBRD_CLOUD_PREFIX).unwrap_or_default();
250	    let runtime =
251	        rbtdrk_read_env_value(&rbrr, RBTDRK_FIELD_RBRR_RUNTIME_PREFIX).unwrap_or_default();
252	    if cloud == cloud_target && runtime == runtime_target {
253	        return Ok(());
254	    }
255	
256	    if cloud != cloud_target {
257	        let content = std::fs::read_to_string(&rbrd)
258	            .map_err(|e| format!("rbtdrk: read {}: {}", rbrd.display(), e))?;
259	        let new_content = rbtdrk_replace_env_fields(
260	            &content,
261	            &[(RBTDRK_FIELD_RBRD_CLOUD_PREFIX, cloud_target.as_str())],
262	        );
263	        std::fs::write(&rbrd, &new_content)
264	            .map_err(|e| format!("rbtdrk: write {}: {}", rbrd.display(), e))?;
265	    }
266	
267	    if runtime != runtime_target {
268	        let content = std::fs::read_to_string(&rbrr)
269	            .map_err(|e| format!("rbtdrk: read {}: {}", rbrr.display(), e))?;
270	        let new_content = rbtdrk_replace_env_fields(
271	            &content,
272	            &[(RBTDRK_FIELD_RBRR_RUNTIME_PREFIX, runtime_target.as_str())],
273	        );
274	        std::fs::write(&rbrr, &new_content)
275	            .map_err(|e| format!("rbtdrk: write {}: {}", rbrr.display(), e))?;
276	    }
277	
278	    let commit_msg = format!(
279	        "canonical-establish fixture: install canonical prefixes ({}/{})",
280	        cloud_target, runtime_target
281	    );
282	    rbtdrk_git_add_and_commit_paths(
283	        root,
284	        &[RBTDGC_RBRR_FILE, RBTDGC_RBRD_FILE],
285	        &commit_msg,
286	    )
287	}
288	
289	fn rbtdrk_install_depot_moniker(root: &Path, moniker: &str) -> Result<(), String> {
290	    let rbrd = root.join(RBTDGC_RBRD_FILE);
291	    let content = std::fs::read_to_string(&rbrd)
292	        .map_err(|e| format!("rbtdrk: read {}: {}", rbrd.display(), e))?;
293	    let new_content =
294	        rbtdrk_replace_env_fields(&content, &[(RBTDRK_FIELD_RBRD_DEPOT_MONIKER, moniker)]);
295	    std::fs::write(&rbrd, &new_content)
296	        .map_err(|e| format!("rbtdrk: write {}: {}", rbrd.display(), e))?;
297	    let commit_msg = format!(
298	        "canonical-establish fixture: set {}={}",
299	        RBTDRK_FIELD_RBRD_DEPOT_MONIKER, moniker
300	    );
301	    rbtdrk_git_add_and_commit(root, RBTDGC_RBRD_FILE, &commit_msg)
302	}
