435	/// Cases 3 and 4 probe: governor RBRA file present at the canonical path.
436	/// Established by case 2's mantle + canonical-copy step.
437	fn rbtdrk_probe_governor_rbra() -> Result<(), String> {
438	    let root = rbtdrk_probe_root()?;
439	    let path = rbtdrk_canonical_rbra(&root, RBTDGC_ACCOUNT_GOVERNOR)?;
440	    if !path.exists() {
441	        return Err(format!("governor RBRA absent at {}", path.display()));
442	    }
443	    Ok(())
444	}
445	
446	// ── Cases ────────────────────────────────────────────────────
447	
448	/// Case 1 — canonical depot levy. Installs canc-/canr- prefixes, picks a
449	/// fresh canest moniker, levies the depot, cross-checks project_id from
450	/// fact-file against the RBDC compose derivation.
451	fn rbtdrk_depot_levy(dir: &Path) -> rbtdre_Verdict {
452	    let probe = rbtdrb_Probe {
453	        name: "rbrr.env present",
454	        check: rbtdrk_probe_rbrr_present,
455	        remediation: "ensure regime is initialized — rerun pristine-lifecycle if needed",
456	    };
457	    if let Err(v) = rbtdrb_assert(&probe) {
458	        return v;
459	    }
460	    rbtdrc_with_ctx(|ctx| rbtdrk_depot_levy_impl(ctx, dir))
461	}
462	
463	fn rbtdrk_depot_levy_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
464	    let root = ctx.project_root().to_path_buf();
465	
466	    if let Err(e) = rbtdrk_install_canonical_prefixes(&root) {
467	        return rbtdre_Verdict::Fail(format!("install canonical prefixes: {}", e));
468	    }
469	
470	    let list_pre = match rbtdrk_invoke_logged(
471	        ctx,
472	        RBTDGC_LIST_DEPOT,
473	        &[],
474	        &[],
475	        dir,
476	        "list-pre",
477	    ) {
478	        Ok(r) => r,
479	        Err(e) => return rbtdre_Verdict::Fail(format!("depot list (pre-levy): {}", e)),
480	    };
481	    if list_pre.exit_code != 0 {
482	        return rbtdre_Verdict::Fail(format!(
483	            "depot list (pre-levy) exit {}\n{}",
484	            list_pre.exit_code, list_pre.stderr
485	        ));
486	    }
487	
488	    let tincture = match rbtdrk_burs_tincture() {
489	        Ok(t) => t,
490	        Err(e) => return rbtdre_Verdict::Fail(format!("read BURS_TINCTURE: {}", e)),
491	    };
492	    let family_stem = rbtdrk_family_stem(&tincture);
493	    let moniker = match rbtdrk_pick_next_moniker(&list_pre, &root, &family_stem) {
494	        Ok(m) => m,
495	        Err(e) => return rbtdre_Verdict::Fail(format!("pick next moniker: {}", e)),
496	    };
497	    if let Err(e) = rbtdrk_install_depot_moniker(&root, &moniker) {
498	        return rbtdre_Verdict::Fail(format!("install depot moniker: {}", e));
499	    }
500	
501	    let levy = match rbtdrk_invoke_logged(
502	        ctx,
503	        RBTDGC_LEVY_DEPOT,
504	        &[],
505	        &[],
506	        dir,
507	        "levy",
508	    ) {
509	        Ok(r) => r,
510	        Err(e) => return rbtdre_Verdict::Fail(format!("depot levy: {}", e)),
511	    };
512	    if levy.exit_code != 0 {
513	        return rbtdre_Verdict::Fail(format!(
514	            "depot levy exit {}\n{}",
515	            levy.exit_code, levy.stderr
516	        ));
517	    }
518	
519	    let list_present = match rbtdrk_invoke_logged(
520	        ctx,
521	        RBTDGC_LIST_DEPOT,
522	        &[],
523	        &[],
524	        dir,
525	        "list-present",
526	    ) {
527	        Ok(r) => r,
528	        Err(e) => return rbtdre_Verdict::Fail(format!("depot list (after levy): {}", e)),
529	    };
530	    if list_present.exit_code != 0 {
531	        return rbtdre_Verdict::Fail(format!(
532	            "depot list (after levy) exit {}\n{}",
533	            list_present.exit_code, list_present.stderr
534	        ));
535	    }
536	
537	    let prefix_dir = match rbtdrk_cloud_prefix_subdir(&root) {
538	        Ok(p) => p,
539	        Err(e) => return rbtdre_Verdict::Fail(format!("resolve cloud_prefix subdir: {}", e)),
540	    };
541	    let fact_path = list_present
542	        .burv_output
543	        .join(RBTDRI_BURV_OUTPUT_SUBDIR)
544	        .join(&prefix_dir)
545	        .join(format!("{}.{}", moniker, RBTDRK_FACT_EXT_DEPOT_PROJECT));
546	    let fact_project_id = match std::fs::read_to_string(&fact_path) {
547	        Ok(s) => s.trim().to_string(),
548	        Err(e) => {
549	            return rbtdre_Verdict::Fail(format!(
550	                "read depot-project fact '{}': {}",
551	                fact_path.display(),
552	                e
553	            ))
554	        }
555	    };
556	    if fact_project_id.is_empty() {
557	        return rbtdre_Verdict::Fail(format!(
558	            "depot-project fact is empty: {}",
559	            fact_path.display()
560	        ));
561	    }
562	    let _ = std::fs::write(dir.join("project-id.txt"), &fact_project_id);
563	
564	    let composed = match rbtdrk_compose_project_id(&root, &moniker) {
565	        Ok(p) => p,
566	        Err(e) => return rbtdre_Verdict::Fail(format!("compose project_id: {}", e)),
567	    };
568	    if composed != fact_project_id {
569	        return rbtdre_Verdict::Fail(format!(
570	            "project_id mismatch: RBDC compose='{}' vs depot-list fact='{}' \
571	             (RBDC kindle derivation diverged from payor creation)",
572	            composed, fact_project_id
573	        ));
574	    }
575	    rbtdre_Verdict::Pass
576	}
577	
578	/// Case 2 — governor mantle. Mantles governor against the canonical depot,
579	/// reads the SA email fact, copies governor RBRA from BURV output to the
580	/// canonical path under RBRR_SECRETS_DIR.
581	fn rbtdrk_governor_mantle(dir: &Path) -> rbtdre_Verdict {
582	    let probe = rbtdrb_Probe {
583	        name: "canonical depot moniker installed",
584	        check: rbtdrk_probe_canonical_moniker,
585	        remediation: "rerun rbtdrk_depot_levy or the full canonical-establish fixture",
586	    };
587	    if let Err(v) = rbtdrb_assert(&probe) {
588	        return v;
589	    }
590	    rbtdrc_with_ctx(|ctx| rbtdrk_governor_mantle_impl(ctx, dir))
591	}
592	
593	fn rbtdrk_governor_mantle_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
594	    let root = ctx.project_root().to_path_buf();
595	
596	    let assay = match rbtdrk_canonical_rbra(&root, RBTDGC_ACCOUNT_ASSAY) {
597	        Ok(p) => p,
598	        Err(e) => return rbtdre_Verdict::Fail(format!("canonical assay RBRA path: {}", e)),
599	    };
600	
601	    let mantle = match rbtdrk_invoke_logged(
602	        ctx,
603	        RBTDGC_MANTLE_GOVERNOR,
604	        &[],
605	        &[],
606	        dir,
607	        "mantle",
608	    ) {
609	        Ok(r) => r,
610	        Err(e) => return rbtdre_Verdict::Fail(format!("governor mantle: {}", e)),
611	    };
612	    if mantle.exit_code != 0 {
613	        return rbtdre_Verdict::Fail(format!(
614	            "governor mantle exit {}\n{}",
615	            mantle.exit_code, mantle.stderr
616	        ));
617	    }
618	
619	    let email = match rbtdri_read_burv_fact(&mantle, RBTDRK_FACT_GOVERNOR_SA_EMAIL) {
620	        Ok(s) => s,
621	        Err(e) => return rbtdre_Verdict::Fail(format!("read governor SA email fact: {}", e)),
622	    };
623	    let _ = std::fs::write(dir.join("governor-sa-email.txt"), &email);
624	
625	    if !assay.exists() {
626	        return rbtdre_Verdict::Fail(format!(
627	            "assay RBRA absent after governor mantle: {}",
628	            assay.display()
629	        ));
630	    }
631	
632	    let canonical = match rbtdrk_canonical_rbra(&root, RBTDGC_ACCOUNT_GOVERNOR) {
633	        Ok(p) => p,
634	        Err(e) => return rbtdre_Verdict::Fail(format!("canonical governor RBRA path: {}", e)),
635	    };
636	    if let Some(parent) = canonical.parent() {
637	        if let Err(e) = std::fs::create_dir_all(parent) {
638	            return rbtdre_Verdict::Fail(format!(
639	                "create governor RBRA dir {}: {}",
640	                parent.display(),
641	                e
642	            ));
643	        }
644	    }
645	    if let Err(e) = std::fs::copy(&assay, &canonical) {
646	        return rbtdre_Verdict::Fail(format!(
647	            "copy assay RBRA → governor canonical {}: {}",
648	            canonical.display(),
649	            e
650	        ));
651	    }
652	    rbtdre_Verdict::Pass
653	}
654	
655	/// Case 3 — retriever invest + access-probe. The access-probe doubles as the
656	/// IAM-propagation gate: the invest tabtarget is responsible for waiting on
657	/// propagation before exiting (or the probe iterates internally). No separate
658	/// propagation-wait case.
659	fn rbtdrk_retriever_invest(dir: &Path) -> rbtdre_Verdict {
660	    let probe = rbtdrb_Probe {
661	        name: "governor RBRA present",
662	        check: rbtdrk_probe_governor_rbra,
663	        remediation: "rerun rbtdrk_governor_mantle or the full canonical-establish fixture",
664	    };
665	    if let Err(v) = rbtdrb_assert(&probe) {
666	        return v;
667	    }
668	    rbtdrc_with_ctx(|ctx| {
669	        rbtdrk_role_invest_impl(
670	            ctx,
671	            dir,
672	            RBTDGC_INVEST_RETRIEVER,
673	            RBTDRK_IDENTITY_RETRIEVER,
674	            RBTDGC_ACCOUNT_RETRIEVER,
675	        )
676	    })
677	}
678	
679	/// Case 4 — director invest + access-probe.
680	fn rbtdrk_director_invest(dir: &Path) -> rbtdre_Verdict {
681	    let probe = rbtdrb_Probe {
682	        name: "governor RBRA present",
683	        check: rbtdrk_probe_governor_rbra,
684	        remediation: "rerun rbtdrk_governor_mantle or the full canonical-establish fixture",
685	    };
686	    if let Err(v) = rbtdrb_assert(&probe) {
687	        return v;
688	    }
689	    rbtdrc_with_ctx(|ctx| {
690	        rbtdrk_role_invest_impl(
691	            ctx,
692	            dir,
693	            RBTDGC_INVEST_DIRECTOR,
694	            RBTDRK_IDENTITY_DIRECTOR,
695	            RBTDGC_ACCOUNT_DIRECTOR,
696	        )
697	    })
698	}
699	
700	/// Shared divest body: invoke the divest colophon for the identity, 404-tolerant
701	/// (the standing SA may be present or already gone). Exercises rbgg_divest_*'s
702	/// revoke-before-delete and poll_until_gone debounce, so the following invest
703	/// hits the create branch against a durably-gone SA.
704	fn rbtdrk_role_divest_impl(
705	    ctx: &mut rbtdri_Context,
706	    dir: &Path,
707	    divest_colophon: &str,
708	    identity: &str,
709	    role: &str,
710	) -> rbtdre_Verdict {
711	    let label = format!("divest-{}", role);
712	    let divest = match rbtdrk_invoke_logged(ctx, divest_colophon, &[identity], &[], dir, &label) {
713	        Ok(r) => r,
714	        Err(e) => return rbtdre_Verdict::Fail(format!("divest {}: {}", role, e)),
715	    };
716	    if divest.exit_code != 0 {
717	        return rbtdre_Verdict::Fail(format!(
718	            "divest {} exit {}\n{}",
719	            role, divest.exit_code, divest.stderr
720	        ));
721	    }
722	    rbtdre_Verdict::Pass
723	}
724	
725	/// Case — director divest. Clears the standing director SA (revoke bindings →
726	/// delete) so the following director invest exercises the create branch.
727	fn rbtdrk_director_divest(dir: &Path) -> rbtdre_Verdict {
728	    let probe = rbtdrb_Probe {
729	        name: "governor RBRA present",
730	        check: rbtdrk_probe_governor_rbra,
731	        remediation: "rerun rbtdrk_governor_mantle or the full canonical-establish fixture",
732	    };
733	    if let Err(v) = rbtdrb_assert(&probe) {
734	        return v;
735	    }
736	    rbtdrc_with_ctx(|ctx| {
737	        rbtdrk_role_divest_impl(
738	            ctx,
739	            dir,
740	            RBTDGC_DIVEST_DIRECTOR,
741	            RBTDRK_IDENTITY_DIRECTOR,
742	            RBTDGC_ACCOUNT_DIRECTOR,
743	        )
744	    })
745	}
746	
747	/// Case — retriever divest. Clears the standing retriever SA (revoke bindings →
748	/// delete) so the following retriever invest exercises the create branch.
749	fn rbtdrk_retriever_divest(dir: &Path) -> rbtdre_Verdict {
750	    let probe = rbtdrb_Probe {
751	        name: "governor RBRA present",
752	        check: rbtdrk_probe_governor_rbra,
753	        remediation: "rerun rbtdrk_governor_mantle or the full canonical-establish fixture",
754	    };
755	    if let Err(v) = rbtdrb_assert(&probe) {
756	        return v;
757	    }
758	    rbtdrc_with_ctx(|ctx| {
759	        rbtdrk_role_divest_impl(
760	            ctx,
761	            dir,
762	            RBTDGC_DIVEST_RETRIEVER,
763	            RBTDRK_IDENTITY_RETRIEVER,
764	            RBTDGC_ACCOUNT_RETRIEVER,
765	        )
766	    })
767	}
768	
769	/// Shared invest body for retriever and director: invest → assert assay
770	/// dropped by the invest tabtarget → copy to canonical role path → access-probe.
771	fn rbtdrk_role_invest_impl(
772	    ctx: &mut rbtdri_Context,
773	    dir: &Path,
774	    invest_colophon: &str,
775	    identity: &str,
776	    role: &str,
777	) -> rbtdre_Verdict {
778	    let root = ctx.project_root().to_path_buf();
779	
780	    let assay = match rbtdrk_canonical_rbra(&root, RBTDGC_ACCOUNT_ASSAY) {
781	        Ok(p) => p,
782	        Err(e) => return rbtdre_Verdict::Fail(format!("canonical assay RBRA path: {}", e)),
783	    };
784	
785	    // Invest is idempotent (RBSRK/RBSDK): a standing-depot rerun rotates the key
786	    // on the existing SA; a freshly-levied depot creates it. Either way the invest
787	    // tabtarget drops the assay RBRA.
788	
789	    let label_invest = format!("invest-{}", role);
790	    let invest = match rbtdrk_invoke_logged(
791	        ctx,
792	        invest_colophon,
793	        &[identity],
794	        &[],
795	        dir,
796	        &label_invest,
797	    ) {
798	        Ok(r) => r,
799	        Err(e) => return rbtdre_Verdict::Fail(format!("invest {}: {}", role, e)),
800	    };
801	    if invest.exit_code != 0 {
802	        return rbtdre_Verdict::Fail(format!(
803	            "invest {} exit {}\n{}",
804	            role, invest.exit_code, invest.stderr
805	        ));
806	    }
807	
808	    if !assay.exists() {
809	        return rbtdre_Verdict::Fail(format!(
810	            "assay RBRA absent after invest-{}: {}",
811	            role,
812	            assay.display()
813	        ));
814	    }
815	
816	    let canonical = match rbtdrk_canonical_rbra(&root, role) {
817	        Ok(p) => p,
818	        Err(e) => return rbtdre_Verdict::Fail(format!("canonical {} RBRA path: {}", role, e)),
819	    };
820	    if let Some(parent) = canonical.parent() {
821	        if let Err(e) = std::fs::create_dir_all(parent) {
822	            return rbtdre_Verdict::Fail(format!(
823	                "create {} RBRA dir {}: {}",
824	                role,
825	                parent.display(),
826	                e
827	            ));
828	        }
829	    }
830	    if let Err(e) = std::fs::copy(&assay, &canonical) {
831	        return rbtdre_Verdict::Fail(format!(
832	            "copy assay RBRA → {} canonical {}: {}",
833	            role,
834	            canonical.display(),
835	            e
836	        ));
837	    }
838	
839	    let probe_colophon = match rbtdrm_credential_check_colophon(role) {
840	        Some(c) => c,
841	        None => return rbtdre_Verdict::Fail(format!("unknown credential role: {}", role)),
842	    };
843	    let probe_result = match rbtdri_invoke_global(ctx, probe_colophon, &[], &[]) {
844	        Ok(r) => r,
845	        Err(e) => {
846	            return rbtdre_Verdict::Fail(format!("access-probe {} invocation: {}", role, e))
847	        }
848	    };
849	    let _ = std::fs::write(
850	        dir.join(format!("probe-{}-stdout.txt", role)),
851	        &probe_result.stdout,
852	    );
853	    let _ = std::fs::write(
854	        dir.join(format!("probe-{}-stderr.txt", role)),
855	        &probe_result.stderr,
856	    );
857	    if probe_result.exit_code != 0 {
858	        return rbtdre_Verdict::Fail(format!(
859	            "access-probe {} exit {}\n{}",
860	            role, probe_result.exit_code, probe_result.stderr
861	        ));
862	    }
863	
864	    rbtdre_Verdict::Pass
865	}
866	
867	// ── Section registry ─────────────────────────────────────────
868	
869	pub static RBTDRK_CASES_CANONICAL_ESTABLISH: &[rbtdre_Case] = &[
870	    case!(rbtdrk_depot_levy),
871	    case!(rbtdrk_governor_mantle),
872	    case!(rbtdrk_retriever_invest),
873	    case!(rbtdrk_director_invest),
874	];
875	
876	pub static RBTDRK_FIXTURE_CANONICAL_ESTABLISH: rbtdre_Fixture = rbtdre_Fixture {
877	    name: RBTDRM_FIXTURE_CANONICAL_ESTABLISH,
878	    disposition: rbtdre_Disposition::StateProgressing,
879	    setup: None,
880	    teardown: None,
881	    cases: RBTDRK_CASES_CANONICAL_ESTABLISH,
882	};
883	
884	// canonical-invest — the no-levy recycle variant shared by skirmish, dogfight,
885	// and blockade. Runs against a depot the operator has levied by hand (no GCP
886	// project created per run). After re-mantling the governor it divests then
887	// re-invests retriever + director, so every run exercises the full teardown →
888	// reinvest cycle: rbgg_divest_*'s revoke-before-delete and poll_until_gone
889	// debounce, then the invest create branch against a durably-gone SA. This
890	// deliberately stresses the IAM eventual-consistency edges (the delete→recreate
891	// read-flap) on every run. Each case carries its own precondition probe
892	// (governor mantle probes the standing depot's moniker; divest/invest probe the
893	// governor). Divest runs in reverse role order, invest in forward order. Sharing
894	// the case fns is the same provenance-vs-behavior split tadmor/moriah exploit
895	// with RBTDRC_CASES_SECURITY.
896	pub static RBTDRK_CASES_CANONICAL_INVEST: &[rbtdre_Case] = &[
897	    case!(rbtdrk_governor_mantle),
898	    case!(rbtdrk_director_divest),
899	    case!(rbtdrk_retriever_divest),
900	    case!(rbtdrk_retriever_invest),
901	    case!(rbtdrk_director_invest),
902	];
903	
904	pub static RBTDRK_FIXTURE_CANONICAL_INVEST: rbtdre_Fixture = rbtdre_Fixture {
905	    name: RBTDRM_FIXTURE_CANONICAL_INVEST,
906	    disposition: rbtdre_Disposition::StateProgressing,
907	    setup: None,
908	    teardown: None,
909	    cases: RBTDRK_CASES_CANONICAL_INVEST,
910	};
911

